const axios = require('axios');

/**
 * FreshBooksApi service class
 * Handles all communication with the FreshBooks REST API.
 * Credentials are loaded from environment variables to keep secrets out of source code.
 */
class FreshBooksApi {
  constructor() {
    // Base URL for the FreshBooks API (e.g. https://api.freshbooks.com)
    this.baseUrl = process.env.FRESHBOOKS_API_URL;

    // Bearer token used to authenticate every request
    this.token = process.env.FRESHBOOKS_API_TOKEN;
  }

  /**
   * Validate that the required environment variables are present.
   * Throws a descriptive error early so misconfiguration is obvious.
   */
  _validateConfig() {
    if (!this.baseUrl) {
      throw new Error(
        'FRESHBOOKS_API_URL is not set. Please add it to your .env file.'
      );
    }
    if (!this.token) {
      throw new Error(
        'FRESHBOOKS_API_TOKEN is not set. Please add it to your .env file.'
      );
    }
  }

  /**
   * Fetch all invoices from the FreshBooks API.
   *
   * FreshBooks returns invoices nested under the accounting system:
   *   GET /accounting/account/{accountId}/invoices/invoices
   * For simplicity in the demo we hit the /invoices path relative to the
   * configured base URL so the caller can point FRESHBOOKS_API_URL at any
   * compatible endpoint (including a mock server).
   *
   * @returns {Promise<Object>} Raw response data from FreshBooks
   */
  async fetchInvoices() {
    // Guard against missing configuration before making a network call
    this._validateConfig();

    try {
      const response = await axios.get(`${this.baseUrl}/invoices`, {
        headers: {
          // FreshBooks uses OAuth 2.0 Bearer tokens
          Authorization: `Bearer ${this.token}`,
          // Request JSON explicitly
          Accept: 'application/json',
        },
        // Reasonable timeout so the server does not hang indefinitely
        timeout: 10000,
      });

      return response.data;
    } catch (error) {
      // Log the full error server-side for debugging while keeping the
      // thrown message generic enough to be safe for client consumption.
      if (error.response) {
        // The request was made and the server responded with a non-2xx status
        console.error(
          'FreshBooks API responded with an error:',
          error.response.status,
          error.response.data
        );
      } else if (error.request) {
        // The request was made but no response was received (network issue)
        console.error(
          'No response received from FreshBooks API:',
          error.message
        );
      } else {
        // Something went wrong while setting up the request
        console.error('Error setting up FreshBooks API request:', error.message);
      }

      throw new Error('Failed to fetch invoices');
    }
  }
}

// Export a singleton so the HTTP client is reused across requests
module.exports = new FreshBooksApi();

const freshBooksApi = require('../services/freshBooksApi');

/**
 * financeController
 * Handles financial data endpoints including FreshBooks invoice retrieval
 * and any future financial overview / summary functionality.
 */

/**
 * GET /api/finance/invoices
 * Fetches all invoices from FreshBooks and returns them as JSON.
 *
 * Success response  – 200 with the raw FreshBooks invoice payload.
 * Failure response  – 500 with a JSON error message safe for the client.
 */
exports.getInvoices = async (req, res) => {
  try {
    const invoices = await freshBooksApi.fetchInvoices();
    return res.status(200).json(invoices);
  } catch (error) {
    // The service already logged the detailed error; return a safe message.
    console.error('financeController.getInvoices error:', error.message);
    return res.status(500).json({ error: 'Failed to fetch invoices' });
  }
};

/**
 * GET /api/finance/overview
 * Returns a high-level financial summary built from seed / cached data.
 * Placeholder for Phase 3 dashboard integration.
 */
exports.getOverview = async (req, res) => {
  try {
    // TODO: replace with real aggregation logic in Phase 3
    const overview = {
      totalRevenue: 0,
      totalExpenses: 0,
      netIncome: 0,
      outstandingInvoices: 0,
    };
    return res.status(200).json(overview);
  } catch (error) {
    console.error('financeController.getOverview error:', error.message);
    return res.status(500).json({ error: 'Failed to fetch financial overview' });
  }
};

const express = require('express');
const router = express.Router();
const financeController = require('../controllers/financeController');

/**
 * Finance Routes
 * Base path: /api/finance  (mounted in app.js)
 *
 * GET /api/finance/invoices  – Fetch all invoices from FreshBooks
 * GET /api/finance/overview  – Fetch high-level financial summary
 */

// Fetch all invoices from FreshBooks
router.get('/invoices', financeController.getInvoices);

// Financial overview / dashboard summary
router.get('/overview', financeController.getOverview);

module.exports = router;
